        /// <summary>
        ///  コマンドキューが満杯で発行できなかった。
        /// </summary>
        QueueFull = -3,
        /// <summary>
        ///  I/O エラー（ファイル読込失敗等）。
        /// </summary>
        IoError = -4,
        /// <summary>
        ///  オーディオデコード失敗。
        /// </summary>
        DecodeError = -5,
        /// <summary>
        ///  バス循環参照を検出した。
        /// </summary>
        BusLoopDetected = -6,
        /// <summary>
        ///  引数が範囲外（NaN, 容量超過 等）。
        /// </summary>
        InvalidArgument = -7,
        /// <summary>
        ///  パニックを `catch_unwind` で捕捉した。
        /// </summary>
        Panic = -100,
        /// <summary>
        ///  その他内部エラー。
        /// </summary>
        InternalError = -101,
    }

    /// <summary>
    ///  距離減衰モデル。`core::AttenuationModel` の ABI ミラー。
    /// </summary>
    internal enum NeziaAttenuationModel : uint
    {
        None = 0,
        Linear = 1,
        InverseDistance = 2,
        Exponential = 3,
    }


}
